INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b8ed5850-3ccd-4ea6-88fa-265c95172485',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java's Type System — Generics, Type Inference, and Why Static Typing Saves You at Scale$escape$,
  $escape$Java is statically typed at compile time, meaning every variable's type is verified before a single byte of bytecode runs. This eliminates entire classes of runtime errors that plague dynamically typed languages. Since Java 10, `var` enables local type inference — the compiler resolves the type from the right-hand side, so you get brevity without sacrificing compile-time safety. Generics, introduced in Java 5, let you write type-safe reusable code without casting. The compiler erases generic type parameters at runtime (type erasure), which means `List<String>` and `List<Integer>` are both just `List` at the JVM level — a tradeoff for backward compatibility. This matters when using reflection or creating generic arrays. Bounded wildcards (`? extends T`, `? super T`) let you express variance precisely: use `extends` for reading, `super` for writing (PECS — Producer Extends, Consumer Super). Ignoring PECS leads to unchecked casts and `ClassCastException` at runtime despite compiling cleanly.$escape$,
  $escape$import java.util.List;

public class TypeSafetyDemo {
    // PECS: Producer Extends
    public static double sumList(List<? extends Number> list) {
        return list.stream().mapToDouble(Number::doubleValue).sum();
    }

    public static void main(String[] args) {
        var integers = List.of(1, 2, 3);       // var infers List<Integer>
        var doubles  = List.of(1.5, 2.5, 3.0); // var infers List<Double>

        System.out.println(sumList(integers)); // 6.0
        System.out.println(sumList(doubles));  // 7.0
    }
}$escape$,
  $escape$java$escape$,
