INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6724111b-e3dd-476b-9385-2153669519aa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Memory Management — Stack, Heap, and What the GC Actually Guarantees$escape$,
  $escape$Java splits memory into stack and heap. Local primitives and references live on the stack — allocated and freed automatically as frames push and pop. Objects live on the heap, managed entirely by the JVM's garbage collector. Unlike Rust's ownership model, Java has no compile-time memory safety guarantees around object lifetimes; the GC handles reachability, not ownership. An object becomes eligible for collection when no strong reference chain exists from a GC root (thread stacks, static fields, JNI refs). Memory leaks in Java are almost always reference leaks — a forgotten static collection, a listener never deregistered, or a ThreadLocal not cleared. G1GC (default since JDK 9) divides the heap into regions and performs concurrent marking to minimize STW pauses. ZGC (JDK 15+) achieves sub-millisecond pauses via load barriers and colored pointers. Java has no destructor equivalent; use try-with-resources for deterministic cleanup of non-memory resources. WeakReference, SoftReference, and PhantomReference let you participate in GC lifecycle without preventing collection.$escape$,
  $escape$import java.lang.ref.WeakReference;

public class MemoryDemo {
    private static final Map<String, WeakReference<ExpensiveObject>> cache = new HashMap<>();

    public static ExpensiveObject get(String key) {
        WeakReference<ExpensiveObject> ref = cache.get(key);
        ExpensiveObject obj = (ref != null) ? ref.get() : null;
        if (obj == null) {
            obj = new ExpensiveObject(key);
            cache.put(key, new WeakReference<>(obj));
        }
        return obj;
    }
}$escape$,
