INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dd4b305d-f373-4559-8768-6ca5e30024bb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Concurrency in 2024 — Threads, CompletableFuture, and Virtual Threads$escape$,
  $escape$Java's concurrency story has three eras. Classic platform threads (java.lang.Thread) are OS-mapped — expensive to create, with a ~1MB stack each. Pooling them via ExecutorService (Executors.newFixedThreadPool) was the standard answer for years.

CompletableFuture (Java 8+) brought async composition: thenApply, thenCompose, and allOf let you chain non-blocking pipelines without callback hell. But under the hood, you're still burning a pool thread on every blocking call — a JDBC query blocks the carrier thread entirely.

Java 21 changed this with virtual threads (Project Loom). Virtual threads are JVM-managed, heap-allocated continuations. You can spawn millions without exhausting OS resources. Crucially, blocking a virtual thread (Thread.sleep, JDBC, socket I/O) parks only the virtual thread — the carrier thread is released back to the ForkJoinPool. The mental model flips: write blocking-style code, get async scalability. Use Executors.newVirtualThreadPerTaskExecutor() as a drop-in for your thread pool. Structured concurrency (StructuredTaskScope, still in preview) adds parent-child lifecycle guarantees on top.$escape$,
  $escape$import java.util.concurrent.*;

void fetchAll(List<String> urls) throws Exception {
    try (var scope = new StructuredTaskScope.ShutdownOnFailure()) {
        List<StructuredTaskScope.Subtask<String>> tasks = urls.stream()
            .map(url -> scope.fork(() -> httpClient.get(url)))
            .toList();

        scope.join().throwIfFailed();

        tasks.stream()
            .map(StructuredTaskScope.Subtask::get)
            .forEach(System.out::println);
    }
}$escape$,
  $escape$kotlin$escape$,
