INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8f41d60e-9e63-4ca5-9acc-2eafbd6ff267',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Error Handling — Checked Exceptions vs Result Types and When to Use Each$escape$,
  $escape$Java's checked exceptions are compile-time-enforced error contracts — if a method declares `throws IOException`, every caller must handle or propagate it. This is unique among mainstream JVM languages. Unchecked exceptions (`RuntimeException` subclasses) bypass this, propagating silently up the call stack until caught or the thread dies.

The problem: checked exceptions leak implementation details through API signatures, and deep propagation means annotating every layer with `throws`. The modern alternative is a `Result<T>` type using Java 17+ sealed interfaces and records. Unlike `Optional<T>`, which models only presence/absence, `Result` carries a typed error value. Java 21 pattern matching makes exhaustive handling ergonomic — the compiler enforces both branches. Libraries like Vavr provide `Either<L, R>` for the same pattern with richer combinators (`map`, `flatMap`, `fold`).

Rule of thumb: use checked exceptions at system boundaries (I/O, network) where recovery is expected and callers need a reminder. Use `Result` for domain logic where errors are first-class values and you want to compose error-prone operations without try-catch pyramids.$escape$,
  $escape$// Sealed Result type (Java 17+)
sealed interface Result<T> permits Result.Ok, Result.Err {
    record Ok<T>(T value) implements Result<T> {}
    record Err<T>(String message) implements Result<T> {}
}

Result<User> findUser(long id) {
    return userRepo.findById(id)
        .<Result<User>>map(Result.Ok::new)
        .orElse(new Result.Err<>("User not found: " + id));
}

// Exhaustive pattern match (Java 21)
switch (findUser(42L)) {
    case Result.Ok<User>(var u) -> process(u);
    case Result.Err<User>(var msg) -> log.warn(msg);
}$escape$,
  $escape$java$escape$,
