INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd51fa65-4340-4157-af61-fe7f17d3e8f1',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Standard Library — What's Built In vs What You Actually Need from Maven$escape$,
  $escape$Java's standard library is vast but has deliberate gaps. For HTTP clients, `java.net.http.HttpClient` (Java 11+) handles modern async requests natively — no Apache HttpClient needed for basic use cases. JSON, however, is conspicuously absent: the JDK has zero JSON support, so Jackson or Gson is non-negotiable. Collections are rich (`java.util`), but for immutable collections with expressive APIs, Guava's `ImmutableList` and `Multimap` remain popular additions. `java.time` (Java 8+) replaced Joda-Time almost entirely — if you're still importing `org.joda.time`, stop. For CSV parsing, the standard library offers nothing; OpenCSV or Apache Commons CSV fills that gap. Logging is a similar story: `java.util.logging` exists but is rarely used in production — SLF4J + Logback is the de facto standard. Cryptography (`javax.crypto`) is solid for AES/RSA, but Bouncy Castle is needed for anything beyond mainstream algorithms. Rule of thumb: `java.net.http`, `java.time`, `java.nio`, and `java.util.concurrent` are now production-grade. JSON, logging, and CSV always need third-party.$escape$,
  $escape$// Built-in HTTP client (Java 11+) — no dependency needed
HttpClient client = HttpClient.newHttpClient();
HttpRequest request = HttpRequest.newBuilder()
    .uri(URI.create("https://api.example.com/data"))
    .GET()
    .build();
HttpResponse<String> response = client.send(request, HttpResponse.BodyHandlers.ofString());
System.out.println(response.statusCode());

// JSON still needs Jackson — JDK has nothing built-in
ObjectMapper mapper = new ObjectMapper();
MyDto dto = mapper.readValue(response.body(), MyDto.class);$escape$,
  $escape$java$escape$,
