INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f66c212e-8ed9-48a7-bc28-9893f04fc7b8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Dependency Locking — Gradle Lock Files, Version Ranges & OWASP Auditing$escape$,
  $escape$Maven has no native lock file — version ranges in pom.xml (`[1.0,2.0)`) silently pull different transitive deps across builds. The pragmatic fix: pin everything in `<dependencyManagement>` or import a BOM like `spring-boot-dependencies`. Gradle 4.8+ solves this properly. Add `dependencyLocking { lockAllConfigurations() }` to `build.gradle.kts`, then run `./gradlew dependencies --write-locks` to generate a `gradle.lockfile` per configuration. Subsequent builds resolve only locked versions — CI builds stop drifting. To update a single dep without regenerating everything: `./gradlew dependencies --update-locks com.google.guava:guava --write-locks`.

For CVE auditing, the OWASP Dependency-Check Gradle plugin scans your full dependency graph against the NVD database. Configure `failBuildOnCVSS = 7f` to gate your pipeline on critical vulnerabilities. When a CVE surfaces in a transitive dep, use `./gradlew dependencyInsight --dependency log4j-core --configuration runtimeClasspath` to trace exactly which direct dependency pulls it in — then add an exclusion at that boundary rather than suppressing the alert globally. Commit `gradle.lockfile` to source control; treat lockfile diffs in PRs the same as code changes.$escape$,
  $escape$// build.gradle.kts
plugins {
    id("org.owasp.dependencycheck") version "9.2.0"
}

dependencyLocking {
    lockAllConfigurations()
}

dependencyCheck {
    failBuildOnCVSS = 7f
    suppressionFile = "owasp-suppressions.xml"
}

dependencies {
    implementation("com.google.guava:guava:33.2.1-jre") // pinned, not a range
}
// Generate: ./gradlew dependencies --write-locks
// Audit:    ./gradlew dependencyCheckAnalyze
// Trace:    ./gradlew dependencyInsight --dependency log4j-core --configuration runtimeClasspath$escape$,
  $escape$kotlin$escape$,
