INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f54dd899-3510-4114-bf23-035db2d8c962',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Microbenchmarking with JMH — Avoiding JIT Illusions$escape$,
  $escape$Raw `System.nanoTime()` loops lie. The JVM's JIT compiler eliminates dead code, speculatively inlines methods, and OSR-compiles hot loops mid-execution — making naive timing useless. JMH (Java Microbenchmark Harness) solves this with controlled warmup iterations, multiple JVM forks, and blackhole consumption to prevent dead-code elimination. A critical JMH subtlety: always return values or pass them to `Blackhole.consume()`, otherwise the JIT will eliminate the entire benchmark body. Use `@BenchmarkMode(Mode.AverageTime)` with `@OutputTimeUnit(TimeUnit.NANOSECONDS)` for tight loops, and fork at least 3 JVM instances (`@Fork(3)`) to separate JIT profiles between benchmark methods. For allocation profiling, add `-prof gc` to surface hidden GC pressure from autoboxing or stream intermediate objects. Pair JMH with async-profiler (`-prof async`) or Java Flight Recorder (`-prof jfr`) to get CPU flame graphs without safepoint bias — a known blind spot in traditional JVMTI profilers that only sample at safepoints, skewing results toward allocation-heavy paths.$escape$,
  $escape$@BenchmarkMode(Mode.AverageTime)
@OutputTimeUnit(TimeUnit.NANOSECONDS)
@Fork(3)
@Warmup(iterations = 5, time = 1)
@Measurement(iterations = 5, time = 1)
@State(Scope.Thread)
public class StringConcatBenchmark {

    @Benchmark
    public String stringPlus() {
        return "Hello" + " " + "World";
    }

    @Benchmark
    public String stringBuilder() {
        return new StringBuilder().append("Hello").append(" ").append("World").toString();
    }
}$escape$,
  $escape$java$escape$,
