INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f6dfe60b-4af4-4b6d-bf7d-9c8463b75272',
  '00000000-0000-0000-0000-000000000001',
  $escape$Java Unit Testing — JUnit 5 Philosophy and What Makes a Test Worth Writing$escape$,
  $escape$JUnit 5 (Jupiter) is the de facto test runner for Java. Unlike JUnit 4's single monolithic jar, JUnit 5 splits into Platform, Jupiter (API), and Vintage (legacy support) — giving you a composable architecture. The philosophy centers on testing behavior, not implementation: assert what the method contract guarantees, not how it achieves it.

Annotations drive the lifecycle: @BeforeEach/@AfterEach replace @Before/@After, and @ExtendWith(MockitoExtension.class) wires Mockito without manual openMocks() calls. Prefer constructor injection in your production classes — it makes @InjectMocks reliable and eliminates field injection surprises.

Parameterized tests via @ParameterizedTest + @MethodSource replace copy-paste test methods. Use @DisplayName for readable failure messages in CI logs — 'should throw when balance is negative' beats 'testThrowWhenBalanceNegative'. Keep each test to a single logical assertion. Mockito's verify() checks interaction contracts, but overusing it couples tests to internals — only verify side effects that matter to callers.$escape$,
  $escape$@ExtendWith(MockitoExtension.class)
class TransferServiceTest {

    @Mock PaymentGateway gateway;
    @InjectMocks TransferService service;

    @ParameterizedTest
    @MethodSource("invalidAmounts")
    @DisplayName("should reject non-positive transfer amounts")
    void rejectsInvalidAmounts(BigDecimal amount) {
        assertThrows(IllegalArgumentException.class,
            () -> service.transfer(amount, "acc-1", "acc-2"));
        verifyNoInteractions(gateway);
    }

    static Stream<BigDecimal> invalidAmounts() {
        return Stream.of(BigDecimal.ZERO, new BigDecimal("-50"));
    }
}$escape$,
  $escape$java$escape$,
